using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary (default: 3).
    /// </summary>
    [Range(1, 100)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalSentenceCount { get; set; }

    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public interface IDocumentSummarizationService
{
    (string Summary, int OriginalSentenceCount, int SummarySentenceCount) Summarize(string text, int maxSentences);
}

/// <summary>
/// Extractive summarizer that ranks sentences by word-frequency score
/// and returns the top-ranked ones in their original order.
/// </summary>
public partial class DocumentSummarizationService : IDocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","in","on","at","to","for",
        "of","with","by","from","as","into","through","during","before","after",
        "above","below","between","out","off","over","under","again","further",
        "then","once","here","there","when","where","why","how","all","each",
        "every","both","few","more","most","other","some","such","no","nor",
        "not","only","own","same","so","than","too","very","it","its","this",
        "that","these","those","i","me","my","we","our","you","your","he","him",
        "his","she","her","they","them","their","what","which","who","whom"
    };

    public (string Summary, int OriginalSentenceCount, int SummarySentenceCount) Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);

        if (sentences.Count <= maxSentences)
        {
            return (string.Join(" ", sentences), sentences.Count, sentences.Count);
        }

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = sentences
            .Select((s, idx) => (Index: idx, Sentence: s, Score: ScoreSentence(s, wordFrequencies)))
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index) // preserve original order
            .Select(x => x.Sentence);

        var summary = string.Join(" ", scored);
        return (summary, sentences.Count, maxSentences);
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                if (!StopWords.Contains(word))
                {
                    freq[word] = freq.GetValueOrDefault(word) + 1;
                }
            }
        }
        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = TokenizeWords(sentence);
        if (words.Count == 0) return 0;

        double total = words
            .Where(w => !StopWords.Contains(w))
            .Sum(w => wordFrequencies.GetValueOrDefault(w));

        return total / words.Count;
    }

    private static List<string> TokenizeWords(string text)
    {
        return WordRegex().Matches(text)
            .Select(m => m.Value)
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z0-9]+\b", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizationService _summarizationService;

    public SummarizeController(IDocumentSummarizationService summarizationService)
    {
        _summarizationService = summarizationService;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var (summary, originalCount, summaryCount) = _summarizationService.Summarize(
            request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount
        });
    }
}

